  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Aaves Scorecard für neue Chains</text>
  <g font-family="sans-serif">
    <rect x="20" y="50" width="205" height="150" rx="10" fill="#0f1a12" stroke="#4ade80" stroke-width="1.6"/>
    <text x="36" y="76" fill="#4ade80" font-size="14" font-weight="700">Monad V3 (Juni)</text>
    <text x="36" y="112" fill="#e4e4e7" font-size="22" font-weight="800">100 Mio. $</text>
    <text x="36" y="134" fill="#a1a1aa" font-size="13">TVL nach 48 Std.</text>
    <text x="36" y="158" fill="#4ade80" font-size="13" font-weight="700">&#10003; Starker Start</text>
    <rect x="248" y="50" width="205" height="150" rx="10" fill="#1a0f0f" stroke="#f87171" stroke-width="1.6"/>
    <text x="264" y="76" fill="#f87171" font-size="14" font-weight="700">zkSync-Relaunch (Juni)</text>
    <text x="264" y="112" fill="#e4e4e7" font-size="22" font-weight="800">&lt;800 Tsd. $</text>
